"use client"

import { useState, useEffect, useMemo } from "react";
import dynamic from "next/dynamic";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { 
  Zap, Loader2, Camera, CarFront,
  Navigation, ShieldAlert, Timer, Flag, Crown, Trophy, Sun
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { useUser, useDoc, useFirestore, useMemoFirebase, addDocumentNonBlocking, useCollection } from "@/firebase";
import { doc, collection, query, where, orderBy, limit } from "firebase/firestore";
import { useDriving, RunMode } from "@/context/driving-context";

const RouteMap = dynamic(() => import("@/components/telemetry/route-map"), { 
  ssr: false,
  loading: () => (
    <div className="w-full h-full flex items-center justify-center bg-zinc-900/50 animate-pulse rounded-3xl">
      <Loader2 className="w-6 h-6 animate-spin text-accent" />
    </div>
  )
});

type ReportType = 'Radar' | 'Polici' | 'Kontrollë';

export default function DashboardPage() {
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  const { 
    speed, isDriving, peakSpeed, tripTime, tripDistance, hasGps, 
    currentCoords, routePoints, telemetry, startTime,
    runMode, dragTime, isDragFinished, isDragActive, isWakeLockActive,
    setRunMode, startTrip, stopTrip, resetTrip 
  } = useDriving();
  
  const [mounted, setMounted] = useState(false);
  const [isReporting, setIsReporting] = useState<ReportType | null>(null);
  const [showSummary, setShowSummary] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  
  const { toast } = useToast();

  const profileRef = useMemoFirebase(() => {
    if (!user?.uid || isUserLoading || !db) return null;
    return doc(db, "users", user.uid);
  }, [user?.uid, isUserLoading, db]);
  const { data: profile } = useDoc(profileRef);

  useEffect(() => {
    setMounted(true);
  }, []);

  // Show summary automatically when drag is finished
  useEffect(() => {
    if (isDragFinished && mounted) {
      setShowSummary(true);
      toast({ title: "Gara u krye!", description: `Koha jote: ${dragTime?.toFixed(2)}s` });
    }
  }, [isDragFinished, dragTime, toast, mounted]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const rpm = useMemo(() => {
    if (speed === 0) return 800;
    const gear = Math.floor(speed / 60) + 1;
    const speedInGear = speed % 60;
    const baseRpm = 1000 + (gear * 200);
    const calculated = baseRpm + (speedInGear * 100);
    return Math.min(calculated, 8000);
  }, [speed]);

  const handleQuickReport = async (type: ReportType) => {
    if (!db || !currentCoords || !user?.uid) {
      toast({ variant: "destructive", title: "Gabim", description: "GPS duhet të jetë aktiv dhe duhet të jeni të kyçur." });
      return;
    }
    setIsReporting(type);
    
    let locationName = profile?.city || "Kosovo";
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${currentCoords.lat}&lon=${currentCoords.lng}&zoom=18&addressdetails=1`);
      const data = await response.json();
      if (data.address) {
        const address = data.address;
        const road = address.road || address.pedestrian || address.street || address.residential || address.suburb || "";
        const area = address.neighbourhood || address.village || address.hamlet || address.city_district || "";
        const city = address.city || address.town || address.municipality || "";
        
        const parts = [road, area, city].filter(Boolean);
        if (parts.length > 0) {
          locationName = parts.slice(0, 2).join(", ");
        }
      }
    } catch (e) {
      console.warn("Geocoding failed");
    }

    const reportsCol = collection(db, "radar_reports");
    addDocumentNonBlocking(reportsCol, {
      type,
      lat: currentCoords.lat,
      lng: currentCoords.lng,
      location: locationName,
      city: profile?.city || "Kosovo",
      createdAt: new Date().toISOString(),
      userId: user?.uid
    });
    
    setTimeout(() => {
      setIsReporting(null);
      toast({ title: "Raportuar!", description: `${type} shënuar në: ${locationName}` });
    }, 500);
  };

  const handleSaveRun = () => {
    if (!user?.uid || !db || !profile) return;
    setIsSaving(true);
    const runData = {
      userId: user.uid,
      username: profile.username,
      carBrand: profile.carBrand,
      carModel: profile.carModel,
      profileIcon: profile.profileIcon,
      city: profile.city || "Prishtinë",
      runType: runMode === 'free' ? 'Top Speed' : runMode === '0-100' ? '0-100' : runMode === '100-200' ? '100-200' : '1/4 Mile',
      startTime: startTime?.toISOString() || new Date().toISOString(),
      endTime: new Date().toISOString(),
      durationSeconds: tripTime,
      peakSpeedKmH: peakSpeed,
      distanceMeters: tripDistance,
      dragTime: dragTime,
      telemetry: telemetry,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      carProfileId: "primary"
    };
    
    // Save to user subcollection
    const userRunsCol = collection(db, "users", user.uid, "runs");
    addDocumentNonBlocking(userRunsCol, runData);
    
    // Save to public leaderboard
    const publicRunsCol = collection(db, "public_runs");
    addDocumentNonBlocking(publicRunsCol, runData);
    
    toast({ title: "Gara u ruajt!", description: "Të dhënat u sinkronizuan me modulin Drag." });
    setIsSaving(false);
    setShowSummary(false);
    resetTrip();
  };

  const getGaugeColor = () => {
    if (runMode === '0-100') return 'text-cyan-400';
    if (runMode === '100-200') return 'text-purple-500';
    if (runMode === '1/4mile') return 'text-yellow-500';
    return speed > 200 ? "text-red-500" : "text-accent";
  };

  if (!mounted || isUserLoading) return <div className="min-h-screen bg-background flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-accent" /></div>;

  return (
    <div className="flex flex-col min-h-full bg-background text-foreground pb-24 overflow-x-hidden safe-top relative no-scrollbar">
      <div className="absolute inset-0 bg-gradient-to-b from-accent/10 via-transparent to-transparent pointer-events-none" />
      
      <div className="p-4 space-y-3 z-20 shrink-0">
        <div className="flex items-center justify-between px-1">
           <div className="flex items-center gap-2">
             <div className={cn("w-2 h-2 rounded-full", isWakeLockActive ? "bg-green-500 animate-pulse shadow-[0_0_8px_#22c55e]" : "bg-red-500")} />
             <span className="text-[7px] font-black uppercase text-muted-foreground tracking-widest">
               {isWakeLockActive ? "EKRANI AKTIV" : "SCREEN LOCK OFF"}
             </span>
           </div>
           {isWakeLockActive && <Sun className="w-3 h-3 text-accent animate-spin-slow" />}
        </div>

        <div className="grid grid-cols-3 gap-3 w-full">
          <Button onClick={() => handleQuickReport('Radar')} disabled={!!isReporting} className="h-14 flex flex-col gap-1 rounded-2xl glass-card bg-red-600/10 border-red-500/20 text-white active:scale-95 transition-all">
            {isReporting === 'Radar' ? <Loader2 className="w-4 h-4 animate-spin text-red-500" /> : <Camera className="w-5 h-5 text-red-500" />}
            <span className="text-[8px] font-black uppercase italic tracking-wider">RADAR</span>
          </Button>
          <Button onClick={() => handleQuickReport('Polici')} disabled={!!isReporting} className="h-14 flex flex-col gap-1 rounded-2xl glass-card bg-blue-600/10 border-blue-500/20 text-white active:scale-95 transition-all">
            {isReporting === 'Polici' ? <Loader2 className="w-4 h-4 animate-spin text-blue-500" /> : <ShieldAlert className="w-5 h-5 text-blue-500" />}
            <span className="text-[8px] font-black uppercase italic tracking-wider">POLICI</span>
          </Button>
          <Button onClick={() => handleQuickReport('Kontrollë')} disabled={!!isReporting} className="h-14 flex flex-col gap-1 rounded-2xl glass-card bg-zinc-800/20 border-white/10 text-white active:scale-95 transition-all">
            {isReporting === 'Kontrollë' ? <Loader2 className="w-4 h-4 animate-spin text-zinc-400" /> : <CarFront className="w-5 h-5 text-zinc-400" />}
            <span className="text-[8px] font-black uppercase italic tracking-wider">CHECK</span>
          </Button>
        </div>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center relative px-4 py-2 overflow-visible">
        <div className="grid grid-cols-4 gap-2 w-full max-w-[400px] mb-6 z-20 px-2">
          {[
            { id: 'free', label: 'FREE', icon: Navigation },
            { id: '0-100', label: '0-100', icon: Zap },
            { id: '100-200', label: '100-200', icon: Timer },
            { id: '1/4mile', label: '1/4 MILE', icon: Flag }
          ].map((mode) => (
            <Button 
              key={mode.id}
              onClick={() => !isDriving && setRunMode(mode.id as RunMode)}
              className={cn(
                "h-12 flex flex-col gap-0.5 rounded-xl border transition-all text-[8px] font-black uppercase px-1 shadow-md",
                runMode === mode.id 
                  ? `bg-accent text-background border-accent scale-105 z-10` 
                  : "bg-white/5 border-white/10 text-muted-foreground hover:bg-white/10",
                isDriving && "opacity-50 cursor-not-allowed"
              )}
            >
              <mode.icon className="w-4 h-4" />
              {mode.label}
            </Button>
          ))}
        </div>

        <div className="relative w-full aspect-square flex items-center justify-center max-w-[340px] mx-auto overflow-visible mb-6">
          <div className="absolute inset-0 bg-accent/5 rounded-full blur-[80px] opacity-20" />
          {/* Circular Gauge */}
          <div className={cn(
            "w-full h-full relative flex items-center justify-center transition-all duration-500 rounded-full",
            speed > 200 ? "shadow-[0_0_30px_rgba(239,68,68,0.3)]" : "shadow-[0_0_30px_rgba(77,224,244,0.3)]"
          )}>
            <div className="absolute inset-0 z-10">
              <svg viewBox="0 0 360 360" className="w-full h-full transform -rotate-90 overflow-visible">
                <circle cx="180" cy="180" r="140" stroke="currentColor" strokeWidth="8" fill="transparent" className="text-white/5" />
                <circle
                  cx="180"
                  cy="180"
                  r="140"
                  stroke="currentColor"
                  strokeWidth="12"
                  fill="transparent"
                  strokeDasharray={2 * Math.PI * 140}
                  style={{ 
                    strokeDashoffset: (2 * Math.PI * 140) - (Math.min(speed, 360) / 360) * (2 * Math.PI * 140),
                    transition: 'stroke-dashoffset 0.5s ease-out'
                  }}
                  className={cn("transition-all duration-500", getGaugeColor())}
                />
              </svg>
            </div>
            
            <div className="z-20 flex flex-col items-center">
              <span className={cn(
                "font-black tracking-tighter tabular-nums leading-none transition-all duration-500 drop-shadow-2xl",
                speed > 99 ? "text-[6.5rem]" : "text-[7.5rem]",
                getGaugeColor()
              )}>
                {speed}
              </span>
              <div className="flex flex-col items-center gap-1 -mt-2">
                <span className={cn("text-[10px] font-black uppercase tracking-[0.4em]", getGaugeColor())}>KM / H</span>
                <div className="bg-black/40 backdrop-blur-xl px-3 py-1 rounded-full border border-white/10 mt-2">
                  <span className="text-[10px] font-black italic text-zinc-300 tabular-nums">{rpm} RPM</span>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="w-full max-w-[340px] z-20 space-y-4">
          <Button 
            onClick={() => { 
              if (isDriving) { 
                setShowSummary(true); 
                stopTrip();
              } else { 
                startTrip();
              } 
            }} 
            className={cn(
              "w-full h-16 rounded-[2rem] font-black text-xl uppercase italic tracking-tighter transition-all shadow-2xl active:scale-95 border-b-4", 
              isDriving 
                ? "bg-red-600 hover:bg-red-700 text-white border-red-800" 
                : "bg-accent hover:bg-accent/90 text-background border-accent/70"
            )}
          >
            {isDriving ? <span>NDALO RRUGËTIMIN</span> : <span>FILLO RRUGËTIMIN</span>}
          </Button>
        </div>
      </div>

      <Dialog open={showSummary} onOpenChange={setShowSummary}>
        <DialogContent className="glass border-white/10 w-[94%] sm:max-w-md max-h-[92vh] overflow-y-auto no-scrollbar rounded-[2.5rem] p-0 shadow-2xl">
          <div className="p-6 space-y-6">
            <DialogHeader className="flex flex-col items-center gap-1.5">
              <div className="w-12 h-12 bg-accent/20 rounded-2xl flex items-center justify-center shadow-xl">
                <Trophy className="w-6 h-6 text-accent" />
              </div>
              <DialogTitle className="text-lg font-black italic uppercase tracking-tighter text-center mt-1">GARA PËRFUNDOI</DialogTitle>
            </DialogHeader>
            
            <div className="space-y-5">
              <div className="h-40 w-full glass-card rounded-[1.8rem] border-white/10 overflow-hidden relative shadow-inner">
                <RouteMap points={routePoints} />
              </div>
              
              <div className="grid grid-cols-2 gap-3">
                {[ 
                  { label: "KOHA TOTAL", val: formatTime(tripTime) }, 
                  { label: "DRAG TIME", val: dragTime ? `${dragTime.toFixed(2)}s` : '--', accent: true }, 
                  { label: "PEAK SPEED", val: `${peakSpeed} km/h`, accent: true }, 
                  { label: "DISTANCA", val: `${(tripDistance / 1000).toFixed(2)} km` } 
                ].map((stat, i) => (
                  <Card key={i} className="bg-white/[0.03] border-white/10 p-3 flex flex-col items-center rounded-xl shadow-lg">
                    <span className="text-[6px] font-black text-muted-foreground uppercase tracking-widest mb-1">{stat.label}</span>
                    <span className={cn("text-xs font-black italic text-white", stat.accent && "text-accent")}>{stat.val}</span>
                  </Card>
                ))}
              </div>
            </div>

            <div className="flex flex-col gap-2.5 pt-2">
              <Button onClick={handleSaveRun} disabled={isSaving} className="w-full h-14 bg-accent hover:bg-accent/90 text-background rounded-[1.5rem] font-black italic uppercase text-xs shadow-xl active:scale-95">RUAJ TË DHËNAT</Button>
              <Button variant="ghost" className="w-full h-10 rounded-xl font-black italic uppercase text-[9px] text-zinc-500 hover:text-white" onClick={() => { setShowSummary(false); resetTrip(); }}>MBYLL PA RUAJTUR</Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
      <BottomNav />
    </div>
  );
}